"use client"

import { useState, useMemo } from "react";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Trophy, Medal, MapPin, Zap, Flame, Crown, Loader2, Clock } from "lucide-react";
import { cn } from "@/lib/utils";
import { useFirestore, useCollection, useMemoFirebase } from "@/firebase";
import { collection, query, where, orderBy, limit } from "firebase/firestore";

export default function LeaderboardPage() {
  const [activeTab, setActiveTab] = useState("top-speed");
  const db = useFirestore();

  // Filtri për 7 ditët e fundit (Ranking Javor)
  const oneWeekAgo = useMemo(() => {
    const d = new Date();
    d.setDate(d.getDate() - 7);
    return d.toISOString();
  }, []);

  // Merr garat publike të 7 ditëve të fundit
  const publicRunsQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(
      collection(db, "public_runs"),
      where("createdAt", ">=", oneWeekAgo),
      orderBy("createdAt", "desc"),
      limit(50)
    );
  }, [db, oneWeekAgo]);

  const { data: rawRuns, isLoading } = useCollection(publicRunsQuery);

  // Llogarit Rankingun për Top Speed (Unique per user)
  const topSpeedRankings = useMemo(() => {
    if (!rawRuns) return [];
    const uniqueUsers: Record<string, any> = {};
    rawRuns.forEach(run => {
      if (!uniqueUsers[run.userId] || run.peakSpeedKmH > uniqueUsers[run.userId].peakSpeedKmH) {
        uniqueUsers[run.userId] = run;
      }
    });
    return Object.values(uniqueUsers).sort((a, b) => b.peakSpeedKmH - a.peakSpeedKmH);
  }, [rawRuns]);

  const weeklyFastest = topSpeedRankings[0] || null;

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 overflow-x-hidden no-scrollbar">
      <div className="p-6 pb-2">
        <div className="flex items-center gap-2 mb-2">
          <Trophy className="w-5 h-5 text-accent" />
          <h1 className="text-xl font-black tracking-tighter uppercase italic">RANKINGU I <span className="text-accent">KOSOVËS</span></h1>
        </div>
        <p className="text-xs text-muted-foreground uppercase font-bold tracking-widest">Rankinget Kosove - Perditesime LIVE</p>
      </div>

      <div className="px-6 mt-4">
        {isLoading ? (
          <Card className="p-10 flex items-center justify-center glass rounded-[2rem]">
            <Loader2 className="w-6 h-6 animate-spin text-accent" />
          </Card>
        ) : weeklyFastest ? (
          <Card className="relative overflow-hidden border-accent/30 bg-gradient-to-br from-accent/10 to-transparent p-5 rounded-[2rem] shadow-2xl shadow-accent/5 group">
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
              <Flame className="w-20 h-20 text-accent animate-pulse" />
            </div>
            
            <div className="relative z-10 flex flex-col gap-4">
              <div className="flex items-center gap-2">
                <Crown className="w-4 h-4 text-accent animate-bounce" />
                <span className="text-[10px] font-black uppercase tracking-[0.2em] text-accent neon-text">
                  MË I SHPEJTI KËTË JAVË NË {weeklyFastest.city.toUpperCase()}
                </span>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <Avatar className="w-14 h-14 rounded-2xl border-2 border-accent/20">
                    <AvatarImage src={`https://picsum.photos/seed/${weeklyFastest.userId}/100/100`} />
                    <AvatarFallback>{weeklyFastest.username?.[0]}</AvatarFallback>
                  </Avatar>
                  <div>
                    <h3 className="text-lg font-black italic uppercase tracking-tighter">{weeklyFastest.username}</h3>
                    <p className="text-[10px] font-bold text-muted-foreground uppercase">{weeklyFastest.carBrand} {weeklyFastest.carModel}</p>
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-3xl font-black italic text-accent drop-shadow-[0_0_10px_rgba(77,224,244,0.3)]">
                    {weeklyFastest.peakSpeedKmH} km/h
                  </div>
                  <div className="flex items-center justify-end gap-1 text-[8px] font-bold text-muted-foreground uppercase">
                    <MapPin className="w-2.5 h-2.5" />
                    {weeklyFastest.city}
                  </div>
                </div>
              </div>
            </div>
            <div className="absolute bottom-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-accent/40 to-transparent" />
          </Card>
        ) : (
          <Card className="p-8 text-center glass border-white/5 rounded-[2rem]">
            <Zap className="w-6 h-6 mx-auto mb-2 text-muted-foreground opacity-20" />
            <p className="text-[10px] font-black uppercase tracking-widest text-muted-foreground italic">Pritet rekordi i parë i javës...</p>
          </Card>
        )}
      </div>

      <Tabs defaultValue="top-speed" onValueChange={setActiveTab} className="w-full px-6 mt-6">
        <TabsList className="grid w-full grid-cols-3 bg-white/5 border border-white/10 h-12 rounded-2xl overflow-hidden p-1">
          <TabsTrigger value="0-100" className="rounded-xl data-[state=active]:bg-accent data-[state=active]:text-background font-bold text-[10px]">0-100 KM/H</TabsTrigger>
          <TabsTrigger value="100-200" className="rounded-xl data-[state=active]:bg-accent data-[state=active]:text-background font-bold text-[10px]">100-200 KM/H</TabsTrigger>
          <TabsTrigger value="top-speed" className="rounded-xl data-[state=active]:bg-accent data-[state=active]:text-background font-bold text-[10px]">SHPEJTËSIA MAX</TabsTrigger>
        </TabsList>

        <TabsContent value="top-speed" className="mt-6 space-y-4">
          {topSpeedRankings.length > 0 ? (
            topSpeedRankings.map((run, index) => (
              <LeaderboardCard key={run.id} driver={{ ...run, name: run.username, car: `${run.carBrand} ${run.carModel}` }} index={index} metric={`${run.peakSpeedKmH} km/h`} isSpeed />
            ))
          ) : !isLoading && (
            <div className="text-center py-20 text-muted-foreground glass rounded-[2rem] border-white/5">
              <Zap className="w-8 h-8 mx-auto mb-4 opacity-20" />
              <p className="text-[10px] font-medium uppercase tracking-widest">Nuk ka gara të regjistruara në 7 ditët e fundit.</p>
            </div>
          )}
        </TabsContent>

        <TabsContent value="0-100" className="mt-6">
          <div className="text-center py-20 text-muted-foreground glass rounded-[2rem] border-white/5">
             <Clock className="w-8 h-8 mx-auto mb-4 opacity-20" />
             <p className="text-[10px] font-medium uppercase tracking-widest italic">Së shpejti: Matja 0-100 LIVE.</p>
          </div>
        </TabsContent>
        
        <TabsContent value="100-200" className="mt-6">
          <div className="text-center py-20 text-muted-foreground glass rounded-[2rem] border-white/5">
             <Clock className="w-8 h-8 mx-auto mb-4 opacity-20" />
             <p className="text-[10px] font-medium uppercase tracking-widest italic">Së shpejti: Matja 100-200 LIVE.</p>
          </div>
        </TabsContent>
      </Tabs>
      <BottomNav />
    </div>
  );
}

function LeaderboardCard({ driver, index, metric, isSpeed = false }: { driver: any, index: number, metric: string, isSpeed?: boolean }) {
  return (
    <Card className={cn(
      "glass border-white/5 p-4 relative overflow-hidden group transition-all duration-300 hover:border-accent/30",
      index === 0 && "border-accent/40 bg-accent/5"
    )}>
      <div className="flex items-center gap-4 relative z-10">
        <div className="flex flex-col items-center justify-center min-w-[32px]">
          {index === 0 ? <Trophy className="w-6 h-6 text-accent neon-text" /> : 
           index === 1 ? <Medal className="w-6 h-6 text-gray-400" /> :
           index === 2 ? <Medal className="w-6 h-6 text-amber-700" /> :
           <span className="text-lg font-black text-muted-foreground">{index + 1}</span>}
        </div>
        
        <Avatar className="w-12 h-12 rounded-2xl border border-white/10">
          <AvatarImage src={`https://picsum.photos/seed/${driver.userId}/100/100`} />
          <AvatarFallback>{driver.name?.[0]}</AvatarFallback>
        </Avatar>

        <div className="flex-1 min-w-0">
          <h3 className="font-bold text-sm truncate uppercase italic tracking-tighter">{driver.name}</h3>
          <p className="text-[10px] text-muted-foreground font-medium truncate uppercase">{driver.car}</p>
          <div className="flex items-center gap-1 mt-1 text-[9px] text-accent/80 font-bold uppercase">
            <MapPin className="w-2.5 h-2.5" />
            {driver.city}
          </div>
        </div>

        <div className="text-right">
          <div className="text-xl font-black italic text-accent drop-shadow-[0_0_8px_rgba(77,224,244,0.2)]">
            {metric}
          </div>
        </div>
      </div>
      <div className="absolute right-[-10px] top-[-10px] text-6xl font-black italic text-white/5 select-none pointer-events-none group-hover:text-white/10 transition-colors">
        #{index + 1}
      </div>
    </Card>
  );
}
